import React, { useEffect, useState } from "react";
import { useNavigate, useParams } from "react-router-dom";
import Button from "./ui/Button";
import Input from "./ui/Input"; // Assurez-vous d'utiliser un composant Input valide

const BookUpdate = () => {
  const { id } = useParams(); // Récupérer l'ID depuis l'URL
  const [bookTitle, setBookTitle] = useState("");
  const [bookDescription, setBookDescription] = useState("");
  const [bookPage, setBookPage] = useState("");
  const navigate = useNavigate();

  // Récupérer les données actuelles du livre
  useEffect(() => {
    fetch(`http://localhost:3000/api/book/${id}`)
      .then((response) => {
        if (!response.ok) {
          throw new Error("Erreur lors de la récupération des données");
        }
        return response.json();
      })
      .then((data) => {
        setBookTitle(data.title);
        setBookDescription(data.description);
        setBookPage(data.page);
      })
      .catch((error) => console.error("Erreur :", error));
  }, [id]);

  // Fonction pour soumettre la mise à jour
  const handleUpdate = () => {
    const updatedBook = {
      title: bookTitle,
      description: bookDescription,
      page: parseInt(bookPage, 10),
    };

    fetch(`http://localhost:3000/api/book/${id}`, {
      method: "PUT",
      headers: {
        "Content-Type": "application/json",
      },
      body: JSON.stringify(updatedBook),
    })
      .then((response) => {
        if (!response.ok) {
          throw new Error("Erreur lors de la mise à jour du livre");
        }
        alert("Livre modifié avec succès !");
        navigate("/bookList"); // Redirection après succès
      })
      .catch((error) => console.error("Erreur :", error));
  };

  return (
    <div className="flex justify-center items-center h-screen">
      <div className="w-[50vh] h-auto bg-gray-100 p-6 rounded-lg shadow-lg">
        <h1 className="text-center text-2xl font-bold mb-4">
          Modifier un Livre
        </h1>

        {/* Champ Titre */}
        <div className="mb-4">
          <Input
            placeholder="Entrez le titre du livre"
            value={bookTitle}
            onChange={(e) => setBookTitle(e.target.value)}
          />
        </div>

        {/* Champ Description */}
        <div className="mb-4">
          <Input
            placeholder="Entrez la description du livre"
            value={bookDescription}
            onChange={(e) => setBookDescription(e.target.value)}
          />
        </div>

        {/* Champ Nombre de Pages */}
        <div className="mb-4">
          <Input
            placeholder="Entrez le nombre de pages"
            type="number"
            value={bookPage}
            onChange={(e) => setBookPage(e.target.value)}
          />
        </div>

        {/* Bouton Submit */}
        <Button
          onClick={handleUpdate}
          className="w-full bg-blue-500 text-white py-2 rounded"
        >
          Modifier
        </Button>
      </div>
    </div>
  );
};

export default BookUpdate;
